window.__QUIZ_DATA__=[{"id":"objective>Geography>2015>1","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the Map of BUTO DISTRICT and use it to answer questions 1 to 10.    What is the scale of the map in statement form?","images":["data:image/png;base64,"],"options":{"A":"One centimetre on the map represents half a kilometre on the ground","B":"One centimetre on the map represents one and half kilometres on the ground","C":"One centimetre on the map represents two kilometres on the ground","D":"One centimetres on the map represents four kilometres on the ground"},"answer":"A","explanation":"The scale of the map us 1km on ground to 2cm on the map. It implies that 1cm on the map is equivalent to 1/2 km on the ground.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>2","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the approximate distance as the crow flies from Mami to Esho?","images":["data:image/png;base64,"],"options":{"A":"12.0 km","B":"9.0 km","C":"3.0 km","D":"1.5 km"},"answer":"C","explanation":"As the crow flies, the approximate distance from Mami to Esho is 3.0 km","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>3","subject":"Geography","year":"2015","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : GEO-POLITICAL ISSUES","question":"Which of the following statements performs administrative function?","images":["data:image/png;base64,"],"options":{"A":"Jaba","B":"Ede","C":"BUTO","D":"lititi"},"answer":"C","explanation":"BUTO happens to be a nodal settlement hence it performs administrative function.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>4","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"In which part of the mapped area is lumbering a likely economic activity?","images":["data:image/png;base64,"],"options":{"A":"Northeast","B":"Southeast","C":"Southwest","D":"Northwest"},"answer":"D","explanation":"In the Northwest, we have an abundance of forest vegetation, hence, lumbering will flourish as an economic activity in this region.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2015>5","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the direction of flow of river Afikpo?","images":["data:image/png;base64,"],"options":{"A":"Southwest","B":"Northeast","C":"Northwest","D":"Southeast"},"answer":"C","explanation":"The direction of flow of River Afikpo is Northwest","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>6","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"What is the settlement pattern of Ede?","images":["data:image/png;base64,"],"options":{"A":"Isolated","B":"Dispersed","C":"Annular","D":"Linear"},"answer":"D","explanation":"Ede has a linear settlement pattern. Others do not have.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>7","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"What is the contour interval of the map?","images":["data:image/png;base64,"],"options":{"A":"25 metres","B":"50 metres","C":"100 metres","D":"150 metres"},"answer":"C","explanation":"The contour interval of the map is showing 100 metres","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>8","subject":"Geography","year":"2015","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Which economic activity could be practiced in the South-eastern part of the mapped area?","images":["data:image/png;base64,"],"options":{"A":"Animal rearing","B":"Lumbering","C":"Trading","D":"Mining"},"answer":"A","explanation":"There is scattered cultivation in the South-eastern part of the mapped area, hence the economic activity that could be practiced is animal rearing.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>9","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Which of the following modes of transport is commonly used in the mapped area?","images":["data:image/png;base64,"],"options":{"A":"River","B":"Road","C":"Rail","D":"Air"},"answer":"B","explanation":"The commonly used means of transport in the mapped area is by road.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>10","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"The distance by road from Mami to BUTO is approximately","images":["data:image/png;base64,"],"options":{"A":"9.0 km","B":"14.0km","C":"23.0km","D":"25.0km"},"answer":"A","explanation":"The distance by road from Mami to BUTO is approximately 18cm which is equivalent to 9.0km.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>11","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The hotest planet is","images":[],"options":{"A":"venus","B":"pluto","C":"mercury","D":"Jupiter"},"answer":"C","explanation":"The hottest planet is Mercury due to its closeness to the sun.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>12","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"When does eclipse of the moon occurs?","images":[],"options":{"A":"when the earth comes between the sun and moon","B":"Whenever the earth rotates through 360o","C":"When the sun comes between the moon and earth","D":"when the earth completes a revolution"},"answer":"A","explanation":"Eclipse of the Moon occur when the earth comes in between the sun and the moon in which the earth will serve as an apaque object which will cast shadows on the moon.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>13","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"The upfolded portion of a fold mountain is called","images":[],"options":{"A":"Sial","B":"Anticline","C":"Syncline","D":"Sill"},"answer":"B","explanation":"Anticline and synclines are most commonly up and down folds that result from compression but due to the n-shape of anticline, it exhibits some upfolded part.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>14","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The part of the earth crust which is made up of silica and alumina is the","images":[],"options":{"A":"sima","B":"mantle","C":"baryshere","D":"sial"},"answer":"D","explanation":"The part of the Earth's crust that is made up of silica and alumina is called the sial. The term 'sial' is a combination of 'silica' and 'alumina', the two most abundant elements in this layer of the crust. The sial is less dense than the sima, which is the layer of the Earth's crust made up of silica and magnesium.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>15","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"During equinox","images":[],"options":{"A":"the Tropic of Cancer experiences longer day than the Tropic of Capricon","B":"all places across the globe experience equal lengths of day and night","C":"The length of day at the Equator is shorter than at the Tropic of Cancer","D":"the moon is star-shaped all through the night all over the world"},"answer":"B","explanation":"An Equinox is commonly regarded as the moment the plane (extended indefinitely in all directions) and during equinox, all places across the globe experience Equal length of day and might.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>16","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Whenever volcanic eruption occurs","images":[],"options":{"A":"a new flat surface emerges","B":"residual mountains are formed","C":"over-thrust fold is formed","D":"gases and molten magma are ejected"},"answer":"D","explanation":"Whenever a volcanic eruption occurs, gases and molten magma are ejected. A volcanic eruption is a natural disaster that can cause massive destruction. It occurs when there is an increase in the pressure of magma in the volcano, and this pressure must be released. The release of this pressure is what causes the eruption, and the magma (now called lava) and gases are ejected out of the volcano.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2015>17","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The extent of coastal erosion depends on the","images":[],"options":{"A":"amount of fresh water supplied by tributaries","B":"depth of ocean water","C":"salinity of the ocean","D":"nature of the waves"},"answer":"D","explanation":"The nature of the waves also determines the extent of castal erosion or Coastal erosion is dependent on nature of the wave)","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>18","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which of the following is a characteristic of igneous rock?","images":[],"options":{"A":"Loose in composition","B":"Arranged in layers","C":"Crystalline in nature","D":"Porous in granular structure"},"answer":"C","explanation":"Igneous rocks are formed from the solidification of magma or lava. This process allows the minerals to form a crystalline structure, making 'Crystalline in nature' the correct answer. The other options are incorrect as igneous rocks are not typically loose in composition, arranged in layers, or porous in granular structure.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>19","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Wind erosion is common in arid areas because","images":[],"options":{"A":"rain are widespread and long lasting","B":"wind speed is high and there are few wind breaks","C":"pressure falls below normal in desert areas","D":"the rock are resistant to heat"},"answer":"D","explanation":"The rocks in arid regions are resistant to heat, hence wind erosion is dominant in arid regions","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>20","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The temperature at the foot of a mountain is 20oC. If the mountain is 6000 meters above sea level, what will be the temperature at the top of the mountain?","images":[],"options":{"A":"-190oC","B":"-16.0oC","C":"14.ooC","D":"19.0oC"},"answer":"D","explanation":"The high Resistance of rocks in an area to het makes wind erosion to be common","marks":"1","difficulty":"3"},{"id":"objective>Geography>2015>21","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Which of the following features could be found in the upper course of rivers?","images":[],"options":{"A":"Ox-bow lakes","B":"Waterfall","C":"Deltas","D":"Leaves"},"answer":"B","explanation":"All rivers have an upper middle and lower course in which the upper Course begins in the hills which can create waterfalls when it carves out layers of soft rocks and leaves a clift of hand rock standing.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>22","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Ash and cinder cones are associated with","images":[],"options":{"A":"ozone depletion","B":"hurricane's activities","C":"earthquakes","D":"volcanic eruption"},"answer":"D","explanation":"Volcanoes are grouped into four main kinds: cinder cones, composite cone, shield cone and laya clones which Ash and Cinder cone are associated with volcanic Eruption.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>23","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Deposition of fine grained sand carried over long distance by wind is known as","images":[],"options":{"A":"chemozem","B":"laterite","C":"loess","D":"podzols"},"answer":"C","explanation":"Loess is a wind-blown sediment composed primarily of silt. It is usually yellowish or brown in color and is capable of maintaining a nearly vertical cliff. It is deposited by wind and is usually found in large areas in the mid-latitudes. Chemozem, laterite, and podzols are types of soils, not wind-deposited sediments.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>24","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The core of the earth is called","images":[],"options":{"A":"mesosphere","B":"lithosphere","C":"hydrosphere","D":"barysphere"},"answer":"D","explanation":"The core of the earth is called the barysphere. The earth's core is the deepest, hottest part of our planet, located beneath the mantle. It is divided into two layers: the outer core, which borders the mantle, and the inner core. The boundary separating these regions is called the Bullen discontinuity. The core is mostly composed of iron and nickel and has temperatures of up to 5700 degrees Celsius.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>25","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following environmental resources is non-renewable?","images":[],"options":{"A":"Rain","B":"Minerals","C":"Water","D":"Oxygen"},"answer":"B","explanation":"Environmental Resources is divided into 2, Renewable and non-Renewable resources. Renewable resources are resources which can be gotten back after it might have been used up, which non-renewable is vise-versa. Example of Renewable Resources are Rain, Oxygen, water, etc., and non-renewable are petroleum, minerals, etc.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>26","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Relief rainfall is common around the","images":[],"options":{"A":"lowland areas","B":"peneplains","C":"highland areas","D":"Sahara Desert"},"answer":"C","explanation":"Relief Rainfall or Orographic Rain is formed when air is forced to cool when it twos over relief features in landscape. Such as hills or mountains which are part of highland areas.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>27","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"Which of the following features is of volcanic origin?","images":[],"options":{"A":"Still","B":"Zeugen","C":"Loess","D":"Gorge"},"answer":"A","explanation":"Sill is one of the features of Volcanic Origin. Others are not.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>28","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The instrument used for measuring atmospheric pressure is","images":[],"options":{"A":"hygrometer","B":"barometer","C":"thermometer","D":"anemometer"},"answer":"B","explanation":"A barometer is an instrument used to measure atmospheric pressure. It works by balancing the weight of a column of mercury in a glass tube against the atmospheric pressure, much like a standard ruler measures size.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>29","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The gradual breakdown of rocks in situ by either physical or chemical process is called","images":[],"options":{"A":"erosion","B":"denudation","C":"weathering","D":"deposition"},"answer":"C","explanation":"Weathering is the gradual breakdown of rocks by either physical or chemical process or it is the gradual breakdown of rock into small tiny particles.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>30","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The forth planet from the sun in the solar system is","images":[],"options":{"A":"Mercury","B":"Uranus","C":"Neptune","D":"Mars"},"answer":"D","explanation":"The fourth planet from the sun in the solar system is Mars. The order of the planets from the sun is Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, and Neptune.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>31","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Which rock types involves stratification?","images":[],"options":{"A":"Metamorphic","B":"Sedimentary","C":"Volcanic","D":"Igneous"},"answer":"C","explanation":"Stratification is a fundamental feature of sedimentary rocks which refers to the way sediments layers are stacked over each other.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>32","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Which type of rainfall occurs when two air masses of different temperatures and other physical properties meet?","images":[],"options":{"A":"Orographic rainfall","B":"Relief rainfall","C":"Cyclonic rainfall","D":"Convectional rainfall"},"answer":"C","explanation":"Cyclonic Rainfall occurs when two air masses of different temperatures and other physical properties meets.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2015>33","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"In which regions can stalactites, swallow holes and caverns be found?","images":[],"options":{"A":"Plateau regions","B":"Coastal regions","C":"Mountainous regions","D":"Limestone regions"},"answer":"D","explanation":"Limestone (CaCO3) region which brings about stalagmite and stalactites due to its Insolubility and it also brings about Swallow holes and Caverns.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>34","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"The remains of eroded highlands in desert and semi-desert environments are commonly called","images":[],"options":{"A":"self dumes","B":"barchans","C":"insertbergs","D":"volcanic plug"},"answer":"C","explanation":"Inselbergs is the remains of eroded highlands in desert and semi-desert Environments","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>35","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : GEOGRAPHIC INFORMATION SYSTEM (GIS)","question":"The time in two X on Longitude 15 oE is 4.00 pm. What will be the time in town Y on longitude 15 oW?","images":[],"options":{"A":"2.00 am.","B":"2.00 pm.","C":"6.00 pm","D":"6.00 am"},"answer":"B","explanation":"Longitude in town x = 15o E at 4.00 pm   Longitude in town y = 15oW   Longitude difference = 15o + 15o = 30o  Recall : 1o = 4 minutes   30o = x minutes   x = 120 minutes = 2 hours     We are going to subtract 2 hours from 4.pm because we are going to meet west before East. 4.00 pm - 2 hours = 2.pm in town Y","marks":"1","difficulty":"3"},{"id":"objective>Geography>2015>36","subject":"Geography","year":"2015","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Which of the following is an advantage of solar energy over other sources of energy?","images":[],"options":{"A":"It is easily renewable","B":"It requires physical gradient difference","C":"ability' to link all parts of a country","D":"ability to withstand bad weather"},"answer":"A","explanation":"The major advantage of solar energy are other source of energy is the characteristics that it posses which is Renewable Characteristics.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>37","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"One relative advantage of water transport over road transport is its","images":[],"options":{"A":"great speed over long distances","B":"capacity for carrying bulky goods","C":"ability to link all parts of a country","D":"ability to withstand bad weather"},"answer":"B","explanation":"Water transport are known to have priority or advantage over road because of it ability to convey or transport bulky goods.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>38","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The number of people living in a unit area of land is termed its","images":[],"options":{"A":"rural depopulation","B":"urban depopulation","C":"rural employment","D":"rural unemployment"},"answer":"D","explanation":"Population density is the number of people living In a unit area of land per time.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>39","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"An effect of rural-urban migration on the source region is","images":[],"options":{"A":"rural depopulation","B":"urban depopulation","C":"rural employment","D":"rural unemployment"},"answer":"A","explanation":"Rural-urban migration refers to the movement of people from rural areas to urban areas. This often leads to rural depopulation as the number of people in rural areas decreases. This is because people move to urban areas in search of better opportunities, services, and living conditions.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>40","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following best explains the high rate of population growth in West Africa?","images":[],"options":{"A":"Birth control policies","B":"High birth rate and low death rate","C":"Low birth rate and high death rate","D":"High rate of immigration"},"answer":"B","explanation":"High birth rate and low death rate really contribute to the excessive growth rate of population In west Africa","marks":"1","difficulty":"3"},{"id":"objective>Geography>2015>41","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following features distinguishes heavy industries from light industries?","images":[],"options":{"A":"Complexities of processing techniques","B":"Amount of waste products generated","C":"Ownership structure of the firm","D":"Source of raw materials"},"answer":"A","explanation":"Light industry is industries that usually are less capital-intensive than heavy industry and in more consumer-oriented than business oriented and also requires complexity of processing techniques.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>42","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"The cheapest mode of transport for the conveyance of bulky goods across countries is","images":[],"options":{"A":"air","B":"land","C":"pipeline","D":"water"},"answer":"D","explanation":"Water transportation is the cheapest mode of transport for the convoyance of bulky goods across countries.","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>43","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The major trading partners of the Anglophone West African countries are","images":[],"options":{"A":"Britain U.S.A Germany and japan","B":"Germany, China, South Africa and Norway","C":"Belgium, India, Columbia and Chile","D":"Chile, Pakistan, Japan and Britain"},"answer":"A","explanation":"Britain, U.S.A, Germany and Japan are the major trading partners of the Anglophone west African countries.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>44","subject":"Geography","year":"2015","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : POPULATION","question":"Which of the following is true of inter community relationship?","images":[],"options":{"A":"Female migrate to rural areas to give birth","B":"Youth migrate to urban areas in search of jobs","C":"Immigrants settle in the city's Central Business District","D":"City dwellers seek schools for their children in rural areas"},"answer":"B","explanation":"The statement 'Youth migrate to urban areas in search of jobs' is true of inter-community relationships. This is a common trend observed globally, where young people move from rural areas to cities in search of better job opportunities and a higher standard of living. This phenomenon is known as urbanization.","marks":"1","difficulty":"3"},{"id":"objective>Geography>2015>45","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"If a country has a population of 20,000,000 and its size is 1,000,000 km2, then its population density is","images":[],"options":{"A":"5 persons l km2","B":"15 persons l km2","C":"20 persons l km2","D":"30 persons l km2"},"answer":"C","explanation":"Populationdensity=no of person in Areasize of the Area  populationdensity=20,000.001,000,000=20 personkm2","marks":"1","difficulty":"1"},{"id":"objective>Geography>2015>46","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following criteria is not important in distinguishing between a village and a town?","images":[],"options":{"A":"Geographical situation","B":"Population size","C":"Range of functions","D":"Variety of activities"},"answer":"A","explanation":"The geographical situation is not a distinguishing factor between a village and a town. The main differences between a village and a town are usually based on factors such as population size, range of functions, and variety of activities. A village is typically smaller in size and has fewer functions and activities compared to a town.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>47","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"One of the usefulness of import tariff on imported goods is the","images":[],"options":{"A":"encouragement of importation from abroad","B":"multiplication of foreign goods in local markets","C":"protection of infant industries","D":"saving of money in foreign accounts"},"answer":"C","explanation":"Import tariffs are taxes imposed on imported goods. One of their main purposes is to protect infant industries. By making imported goods more expensive, they encourage consumers to buy locally produced goods, thus helping new or 'infant' industries to grow.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>48","subject":"Geography","year":"2015","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : ECOWAS","question":"One of the problems limiting the achievement of the objectives of the economic Community of West Africa States is","images":[],"options":{"A":"use of common currency","B":"strong colonial ties","C":"climatic differences","D":"similarity in language"},"answer":"A","explanation":"Using of common currency is a limiting factor to achievement of the objectives of the (ECOWAS)","marks":"1","difficulty":"3"},{"id":"objective>Geography>2015>49","subject":"Geography","year":"2015","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"Cattle ranching is not common in the forest regions of West Africa because of the","images":[],"options":{"A":"scarcity of grass for fodder","B":"presence of tsetse flies","C":"absence of Fulani herdsmen","D":"presence of wild life"},"answer":"B","explanation":"Cattle ranching is not common in the forest regions of West Africa mainly because of the presence of tsetse flies. Tsetse flies are vectors of trypanosomiasis, a disease that affects both humans and animals, especially cattle. The disease, also known as sleeping sickness in humans and nagana in animals, is fatal and has been a major deterrent to cattle rearing in the region. The scarcity of grass for fodder, absence of Fulani herdsmen, and presence of wildlife are not the main reasons why cattle ranching is not common in the forest regions of West Africa.","marks":"1","difficulty":"2"},{"id":"objective>Geography>2015>50","subject":"Geography","year":"2015","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The location of market gardening near large cities is best explained by","images":[],"options":{"A":"availability of power","B":"fertile soil","C":"perishability of products","D":"efficient transportation"},"answer":"C","explanation":"perishability is used in marketing to describe the way in which service capacity cannot be stored for sale in future. In which perishability of products prompt the siting of market gardening near large cities.","marks":"1","difficulty":"2"}];